//! Protobuf contract for the Kerolox compute engine, generated by
//! `connectrpc-build` from `proto/kerolox/v1/kerolox.proto`.

connectrpc::include_generated!();

#[cfg(test)]
mod tests {
    use super::kerolox::v1::*;

    #[test]
    fn access_request_default_is_empty() {
        let req = AccessRequest::default();
        assert!(req.start_time_iso.is_empty());
        assert_eq!(req.duration_seconds, 0.0);
        assert!(req.satellites.is_empty());
        assert!(req.aoi_ids.is_empty());
        assert!(req.comparators.is_empty());
    }

    #[test]
    fn access_pair_result_default_source_unspecified() {
        let r = AccessPairResult::default();
        assert!(r.comparator_id.is_empty());
        assert!(r.source == ResultSource::RESULT_SOURCE_UNSPECIFIED);
    }

    #[test]
    fn satellite_orbital_elements_constructs_with_values() {
        let s = SatelliteOrbitalElements {
            id: "sat-1".into(),
            sma_m: 7_000_000.0,
            ecc: 0.001,
            inc_rad: 0.9,
            raan_rad: 0.1,
            aop_rad: 0.0,
            true_anomaly_rad: 0.0,
            plane: 0,
            index_in_plane: 0,
            __buffa_unknown_fields: Default::default(),
        };
        assert_eq!(s.id, "sat-1");
        assert!((s.sma_m - 7_000_000.0).abs() < 1e-9);
        assert_eq!(s.plane, 0);
    }
}
